// pqStringArray formats a []string as a Postgres array literal, e.g.
// {"a","b"}. lib/pq does not marshal []string automatically for ANY($1).
func pqStringArray(values []string) string {
	out := "{"
	for i, v := range values {
		if i > 0 {
			out += ","
		}
		out += `"` + v + `"`
	}
	return out + "}"
}

