    const parsed = new URL(url);
    if (parsed.hostname.length === 0) return false;
    if (LOCAL_HOSTNAMES.has(parsed.hostname)) {
      const port = parsed.port || (parsed.protocol === "https:" ? "443" : "80");
      if (FORBIDDEN_PORTS.has(port)) return false;
    }
    return true;
  } catch {
    return false;
  }
