  $stepOk    = Run-Step $stepName { node $guardPath }
  $results  += [pscustomobject]@{ step = $stepName; ok = $stepOk }
}

$failed = @($results | Where-Object { -not $_.ok })
$status = if ($failed.Count -eq 0) { "PASS" } else { "FAIL" }
